const input = $input.first().json;
const body = input.body || input;

const brands = body.brands;
if (!brands || brands.length === 0) {
  throw new Error('Se requieren marcas (brands).');
}

const email = body.email || body.clientEmail || '';
if (!email) throw new Error('Se requiere email del cliente.');

const nombre = (body.nombre || '') + ' ' + (body.apellido || '');
const myBrand = body.myBrand || brands[0];
const plan = body.plan || 'basic';

return [{ brands, email, nombre: nombre.trim(), myBrand, plan }];

const sheetResp = $('Create Google Sheet').first().json;
const sheetId = sheetResp.spreadsheetId;

if (!sheetId) {
  throw new Error('No se pudo crear el Sheet. Respuesta: ' + JSON.stringify(sheetResp));
}

const config = $('Validate Input').first().json;

// URL con sheetId + myBrand para que el badge del header sea correcto
const dashboardUrl = 'https://smart-social-ai.vercel.app/Instagram_Intelligence%20(24).html?id=' + sheetId + '&myBrand=' + encodeURIComponent(config.myBrand) + '&plan=' + (config.plan || 'basic');

return [{
  sheetId,
  dashboardUrl,
  brands: config.brands,
  email: config.email,
  nombre: config.nombre,
  myBrand: config.myBrand,
  plan: config.plan
}];
